#!/usr/bin/env python3
"""Authoring + merge tool for the functional-pattern batch (12-example sets).

Builds full advanced-pattern records matching the ORIGINAL set convention:
- exactly 12 varied examples per language (person x polarity x context variety);
- EN + DE, each with formula, example, translation and a Russian gloss per example;
- same top-level schema as data/advanced-patterns.json.

Restores are handled externally; this script appends 24 records to the 236 base.

Run:  python3 inbox/build_new_patterns.py
"""
import json
from datetime import datetime, timezone

SRC = "data/advanced-patterns.json"
GEN_AT = datetime.now(timezone.utc).strftime("%Y-%m-%dT%H:%M:%S.") + "000Z"


def L(formula, example, translation, examples):
    return {
        "formula": formula,
        "example": example,
        "translation": translation,
        "examples": [{"text": t, "translation_ru": r} for (t, r) in examples],
    }


def P(pid, group, title_ru, metaphor_ru, en, de):
    return {
        "id": pid,
        "group_id": group,
        "title_ru": title_ru,
        "metaphor_ru": metaphor_ru,
        "langs": [dict(lang="en", **en), dict(lang="de", **de)],
        "formulas": [en["formula"], de["formula"]],
        "gen": {
            "status": "generated",
            "iterations": 1,
            "lastGeneratedAt": GEN_AT,
            "languages": ["en", "de"],
            "notes": "functional-batch-1",
        },
    }


