def main():
    data = json.load(open(SRC, encoding="utf-8"))
    existing = {p["id"].lower() for p in data}
    added = 0
    for rec in NEW:
        if rec["id"].lower() in existing:
            raise SystemExit(f"Duplicate id would be introduced: {rec['id']}")
        data.append(rec)
        existing.add(rec["id"].lower())
        added += 1
    with open(SRC, "w", encoding="utf-8") as f:
        json.dump(data, f, indent=2, ensure_ascii=False)
        f.write("\n")
    print(f"Added {added} new patterns. Total now: {len(data)}")


if __name__ == "__main__":
    main()
